export const MekongHead={dnsPrefetch: [ 'fonts.googleapis.com','fonts.gstatic.com','cdn.jsdelivr.net','esm.run' ],defaults:{charset: 'UTF-8',viewport: 'width=device-width,initial-scale=1.0',themeColor: '#00e5ff',baseUrl: 'https://sadecmarketinghub.com'},render(title='Mekong Agency',description='RaaS Agency Platform',options={}){const{canonical,ogImage,ogType='website',noDnsPrefetch=false}=options;const url=canonical||`${this.defaults.baseUrl}${window.location.pathname}`;const imageUrl=ogImage||`${this.defaults.baseUrl}/favicon.png`;let html=`<!--SHARED HEAD START--><meta charset="${this.defaults.charset}"><meta name="viewport" content="${this.defaults.viewport}"><meta name="theme-color" content="${this.defaults.themeColor}"><!--SEO--><title>${this.escapeHtml(title)}</title><meta name="description" content="${this.escapeHtml(description)}"><link rel="canonical" href="${this.escapeHtml(url)}"><!--Open Graph--><meta property="og:title" content="${this.escapeHtml(title)}"><meta property="og:description" content="${this.escapeHtml(description)}"><meta property="og:type" content="${ogType}"><meta property="og:url" content="${this.escapeHtml(url)}"><meta property="og:image" content="${imageUrl}"><!--Twitter Card--><meta name="twitter:card" content="summary_large_image"><meta name="twitter:title" content="${this.escapeHtml(title)}"><meta name="twitter:description" content="${this.escapeHtml(description)}"><meta name="twitter:image" content="${imageUrl}"><!--Favicon--><link rel="icon" type="image/png" href="/favicon.png">`;if(!noDnsPrefetch){html+='\n<!--DNS Prefetch-->\n';this.dnsPrefetch.forEach(domain=>{html+=`<link rel="dns-prefetch" href="https://${domain}">\n`;});}if(options.stylesheets){html+='\n<!--Additional Stylesheets-->\n';options.stylesheets.forEach(css=>{html+=`<link rel="stylesheet" href="${css}">\n`;});}html+='\n<!--SHARED HEAD END-->\n';return html;},renderMinimal(title='Component'){return `<meta charset="${this.defaults.charset}"><meta name="viewport" content="${this.defaults.viewport}"><title>${this.escapeHtml(title)}</title><link rel="icon" type="image/png" href="/favicon.png">`.trim();},escapeHtml(str){if(!str)return '';const div=document.createElement('div');div.textContent=str;return div.innerHTML;},inject(title,description,options={}){const headHtml=this.render(title,description,options);const tempDiv=document.createElement('div');tempDiv.innerHTML=headHtml;Array.from(tempDiv.children).forEach(child=>{document.head.appendChild(child);});}};if(typeof window!=='undefined'&&typeof document!=='undefined'){const script=document.currentScript;if(script&&script.dataset.autoHead==='true'){const title=script.dataset.title||'Mekong Agency';const description=script.dataset.description||'RaaS Agency Platform';MekongHead.inject(title,description);}}export default MekongHead;if(typeof module!=='undefined'&&module.exports){module.exports=MekongHead;}